// Consumer Filesystem Layout (single-source moorings path vocabulary)
//   :rbmm_moorings_dir: — plain-text root; the ONLY place the literal moorings
//     directory name appears. Mirrors bash fact-locale RBCC_moorings_dir /
//     BUBC_moorings_dir. Every quoin below composes its display from it.
//   rbsld_ = Spec Layout Directory     rbsrf_ = Spec Regime File
//   Templated regime files (rbrn, rbrv) are composed in prose from
//     {rbsld_*} + {rbrn_moniker}|{rbrv_sigil} + filename (no monolithic quoin).
:rbmm_moorings_dir: rbmm_moorings
:rbsld_moorings:             <<rbsld_moorings,{rbmm_moorings_dir}/>>
